#!/usr/bin/env node
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.join(path.dirname(fileURLToPath(import.meta.url)), "..");
const files = [
  "supabase/migrations/20260718120000_academy_b2b_cme.sql",
  "supabase/migrations/20260718120100_academy_b2b_cme_seed.sql",
];
const parts = files.map((rel) => ({
  name: path.basename(rel),
  sql: fs.readFileSync(path.join(root, rel), "utf8"),
}));
const outPath = path.join(root, "lib/academy/b2b/embedded-migrations.ts");
const out =
  "/** Auto-generated by scripts/generate-academy-b2b-embedded-sql.mjs — do not edit. */\n" +
  "export const ACADEMY_B2B_MIGRATION_SQL: { name: string; sql: string }[] = " +
  JSON.stringify(parts, null, 2) +
  ";\n";
fs.mkdirSync(path.dirname(outPath), { recursive: true });
fs.writeFileSync(outPath, out);
console.log("wrote", outPath, "bytes=" + out.length);
